import React, { forwardRef, useRef, useMemo } from 'react'
import { useGLTF } from '@react-three/drei'
import * as THREE from 'three'

export const RocketModel = forwardRef((props, ref) => {
    const bodyMap = useMemo(() => {
        const tex = new THREE.TextureLoader().load('/scenes3d/Rocket Body.png')
        tex.flipY = false
        tex.encoding = THREE.sRGBEncoding
        return tex
    }, [])
    const windowMap = useMemo(() => {
        const tex = new THREE.TextureLoader().load('/scenes3d/Rocket Window.png')
        tex.flipY = false
        tex.encoding = THREE.sRGBEncoding
        return tex
    })

    const bodyRef = useRef()
    const finRef = useRef()
    const windowRef = useRef()
    const rocket = useGLTF('/scenes3d/rocket.glb')
    const { nodes } = rocket

    return (
        <group ref={ref} {...props} rotation={[0, Math.PI * 0.5, 0]}>
            <mesh
                receiveShadow={true}
                ref={bodyRef}
                geometry={nodes.Rocket_body.geometry}
                position={nodes.Rocket_body.position}
                scale={nodes.Rocket_body.scale}
            >
                <meshStandardMaterial map={bodyMap} metalness={1} roughness={0.5} />
            </mesh>
            <mesh
                ref={windowRef}
                geometry={nodes.Rocket_window.geometry}
                position={nodes.Rocket_window.position}
                rotation={nodes.Rocket_window.rotation}
                scale={nodes.Rocket_window.scale}
                castShadow={true}
            >
                <meshStandardMaterial map={windowMap} metalness={1} roughness={0.5} />
            </mesh>
            <mesh
                ref={finRef}
                geometry={nodes.Rocket_fin.geometry}
                position={nodes.Rocket_fin.position}
                scale={nodes.Rocket_fin.scale}
                castShadow={true}
            >
                <meshStandardMaterial color="red" metalness={1} roughness={0.5} />
            </mesh>
            <mesh
                geometry={nodes.Rocket_hatch_window.geometry}
                rotation={nodes.Rocket_hatch_window.rotation}
                scale={nodes.Rocket_hatch_window.scale}
                castShadow={true}
            >
                <meshStandardMaterial map={windowMap} metalness={1} roughness={0.5} />
            </mesh>
        </group>
    )
})

RocketModel.displayName = 'RocketModel'
