import React, { createRef, useEffect, useMemo } from 'react'
import PropTypes from 'prop-types'
import { useFrame } from '@react-three/fiber'
import { RocketModel } from './RocketModel'
import { Points, PointMaterial, Sphere } from '@react-three/drei'

const SphericalStarsLayer = ({ radius = 10, color = 'white', size = 0.1, count = 500 }) => {
    const positions = useMemo(() => {
        const points = new Float32Array(3 * count)
        for (let i = 0; i < points.length; i += 3) {
            const z = 1 - 2 * Math.random()
            const r = Math.sqrt(Math.max(0, 1 - z * z))
            const phi = 2 * Math.PI * Math.random()

            points[i] = r * Math.cos(phi) * radius
            points[i + 1] = Math.sin(phi) * radius
            points[i + 2] = z * radius
        }
        return points
    }, [])

    return (
        <Points positions={positions} stride={3} frustumCulled={false}>
            <PointMaterial transparent color={color} size={size} sizeAttenuation={true} depthWrite={false} />
        </Points>
    )
}
SphericalStarsLayer.propTypes = {
    radius: PropTypes.number,
    color: PropTypes.string,
    size: PropTypes.number,
    count: PropTypes.number,
}
export const RocketScene = () => {
    const rocketRef = createRef()
    const starsRef = createRef()
    useEffect(() => {
        console.log(Sphere)
    }, [])

    useFrame(() => {
        if (rocketRef.current) {
            rocketRef.current.rotation.y += 0.0015
        }
        if (starsRef.current) {
            starsRef.current.rotation.x = 0.0001
            starsRef.current.rotation.y -= 0.0001
        }
    }, 1)
    return (
        <group>
            <pointLight intensity={5} position={[-20, -30, 530]} color="#11aaee" />
            <pointLight intensity={5} position={[10, 15, 10]} color="#11aaee" />
            <directionalLight
                intensity={30}
                position={[-100, 200, 0]}
                castShadow
                shadow-mapSize-width={2048}
                shadow-mapSize-height={2048}
            />
            <group ref={starsRef}>
                <SphericalStarsLayer />
                <SphericalStarsLayer radius={30} count={500} />
                <SphericalStarsLayer radius={30} count={500} size={0.2} />
                <SphericalStarsLayer radius={50} count={3000} />
            </group>
            <group position={[1, -0.5, 0.0]} rotation={[0, 0.5, -0.8]}>
                <RocketModel ref={rocketRef} />
                <Sphere position={[0, -3, 0]} args={[0.5, 8, 25]} scale={[1, 4, 1]}>
                    <meshLambertMaterial
                        emissive="#ff1111"
                        specular="black"
                        color="black"
                        opacity={0.8}
                        transparent={true}
                    />
                </Sphere>
            </group>
        </group>
    )
}
